<template><el-card><template #header>资产总目录</template><PageToolbar><el-input v-model="q" placeholder="搜索资产名称/业务域" clearable /><el-select v-model="type" placeholder="资产类型" clearable><el-option v-for="i in types" :key="i" :label="i" :value="i"/></el-select><el-select v-model="status" placeholder="状态" clearable><el-option label="已发布" value="published"/><el-option label="审核中" value="reviewing"/><el-option label="草稿" value="draft"/></el-select><el-select v-model="health" placeholder="健康度" clearable><el-option v-for="i in ['A','B','C','D','E']" :key="i" :label="i" :value="i"/></el-select><template #actions><el-button type="primary" @click="newDialog=true">新建资产</el-button></template></PageToolbar><DataTable :data="filtered"><el-table-column prop="name" label="资产名称" min-width="220"/><el-table-column prop="type" label="资产类型"/><el-table-column prop="domain" label="业务域"/><el-table-column prop="region" label="适用区域"/><el-table-column label="状态"><template #default="s"><StatusTag :value="s.row.status"/></template></el-table-column><el-table-column label="健康度"><template #default="s"><HealthScore :level="s.row.health"/></template></el-table-column><el-table-column prop="version" label="当前版本"/><el-table-column prop="updatedAt" label="最近更新时间" width="170"/><el-table-column label="操作" fixed="right" width="330"><template #default="s"><el-button link type="primary" @click="show(s.row)">详情</el-button><el-button link @click="edit(s.row)">编辑</el-button><el-button link @click="s.row.status='compiled'">智能编译</el-button><el-button link type="warning" @click="s.row.status='reviewing'">提交审核</el-button><el-button link type="success" @click="s.row.status='published'">发布</el-button><el-button link type="danger" @click="s.row.status='deprecated'">废止</el-button></template></el-table-column></DataTable><DetailDrawer v-model="drawer" :title="current?.name || '资产详情'"><el-tabs><el-tab-pane label="基础信息"><el-descriptions :column="2" border><el-descriptions-item v-for="(v,k) in current" :key="k" :label="String(k)">{{v}}</el-descriptions-item></el-descriptions></el-tab-pane><el-tab-pane label="元数据">文号、发布单位、生效日期、归属部门等元数据。</el-tab-pane><el-tab-pane label="关联知识切片">{{chunks.slice(0,3).map(i=>i.content).join('；')}}</el-tab-pane><el-tab-pane label="关联规则">{{rules.map(i=>i.name).join('、')}}</el-tab-pane><el-tab-pane label="关联技能">{{skills.slice(0,2).map(i=>i.name).join('、')}}</el-tab-pane><el-tab-pane label="版本记录">{{versions.filter(i=>i.assetName===current?.name).map(i=>i.version).join(' / ')}}</el-tab-pane><el-tab-pane label="调用记录">近 7 日调用 1286 次，异常 3 次。</el-tab-pane><el-tab-pane label="健康度评分">权威性 92，完整性 86，时效性 90。</el-tab-pane></el-tabs></DetailDrawer><el-dialog v-model="newDialog" :title="form.id?'编辑资产':'新建资产'" width="620"><el-form label-width="100"><el-form-item label="资产名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="资产类型"><el-select v-model="form.type"><el-option v-for="i in types" :key="i" :label="i" :value="i"/></el-select></el-form-item><el-form-item label="业务域"><el-input v-model="form.domain"/></el-form-item><el-form-item label="适用区域"><el-input v-model="form.region"/></el-form-item></el-form><template #footer><el-button @click="newDialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></el-card></template>
<script setup lang="ts">import { computed, ref } from 'vue'; import PageToolbar from '@/components/PageToolbar.vue'; import DataTable from '@/components/DataTable.vue'; import DetailDrawer from '@/components/DetailDrawer.vue'; import StatusTag from '@/components/StatusTag.vue'; import HealthScore from '@/components/HealthScore.vue'; import { assets as mockAssets, chunks, rules, skills, versions } from '@/mock/data'; import type { Asset } from '@/types'; const rows=ref<Asset[]>(JSON.parse(JSON.stringify(mockAssets))); const q=ref(''),type=ref(''),status=ref(''),health=ref(''); const types=[...new Set(mockAssets.map(a=>a.type))]; const filtered=computed(()=>rows.value.filter(a=>(!q.value||JSON.stringify(a).includes(q.value))&&(!type.value||a.type===type.value)&&(!status.value||a.status===status.value)&&(!health.value||a.health===health.value))); const drawer=ref(false); const current=ref<Asset>(); const newDialog=ref(false); const form=ref<Partial<Asset>>({}); function show(a:Asset){current.value=a;drawer.value=true} function edit(a:Asset){form.value={...a};newDialog.value=true} function save(){ if(form.value.id){Object.assign(rows.value.find(i=>i.id===form.value.id)!,form.value)}else rows.value.unshift({id:`A${Date.now()}`,name:form.value.name||'新资产',type:form.value.type||'政策文件',domain:form.value.domain||'通用',region:form.value.region||'全省',status:'draft',health:'B',version:'v0.1',updatedAt:'刚刚',owner:'管理员',description:'新建资产'}); newDialog.value=false; form.value={} }</script>
